steps.script:
(content) => {
  const editor = document.querySelector('div.ProseMirror[contenteditable="true"]');
  if (!editor) return { success: false };
  editor.focus();
  const sel = window.getSelection();
  if (sel) {
    const range = document.createRange();
    range.selectNodeContents(editor);
    sel.removeAllRanges();
    sel.addRange(range);
  }
  let inserted = false;
  try { inserted = document.execCommand('insertHTML', false, content); } catch (e) {}
  if (!inserted || !editor.innerHTML || editor.innerHTML.trim() === '' || editor.innerHTML.trim() === '<p></p>') {
    editor.innerHTML = content;
    editor.dispatchEvent(new Event('input', { bubbles: true }));
    editor.dispatchEvent(new Event('change', { bubbles: true }));
  }
  return { success: !!(editor.innerHTML && editor.innerHTML.trim() !== '' && editor.innerHTML.trim() !== '<p></p>') };
}
